@app.get("/login")
async def login():
    auth_url = f"{AUTH_URL}?client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&response_type=code&scope={','.join(SCOPES)}"
    return {"url": auth_url}

@app.get("/login/callback")
async def login_callback(code: str = Depends(OAuth2AuthorizationCodeRequestForm)):
    token_url = TOKEN_URL
    data = {
        "code": code,
        "client_id": CLIENT_ID,
        "client_secret": CLIENT_SECRET,
        "redirect_uri": REDIRECT_URI,
        "grant_type": "authorization_code",
    }
    response = requests.post(token_url, data=data)
    token = response.json()["access_token"]

    # Verify the token using Google's id_token library
    idinfo = id_token.verify_oauth2_token(token, requests.Request(), CLIENT_ID)

    # Use the user's email address as the authentication token
    return {"access_token": idinfo["email"], "token_type": "bearer"}
